import { 神將身, 武拳, 垂臂, 叉腰臂 } from './shinsho.js';
export const 招杜羅 = (bi) => 神將身(bi, {
    臂(bi, 筆) {
        const { M, L, Qk, S, 衣, 細 } = 筆;
        // 垂劍：鋒下——頭上鍔下，刃至脛側而止
        衣(() => {
            bi.A(14.25, 52.0, 0.55); // 頭（柄首）
            M(13.8, 52.45);
            L(13.8, 55.9);
            S(); // 柄貫拳（拳蔽自斷其中段）
            M(14.7, 52.45);
            L(14.7, 55.9);
            S();
            M(12.9, 57.7);
            Qk(14.25, 58.5, 15.6, 57.7);
            S(); // 鍔
            M(13.05, 58.35);
            Qk(14.25, 59.05, 15.45, 58.35);
            S();
            M(13.78, 58.9);
            L(13.98, 85.6);
            S(); // 刃雙緣收鋒
            M(14.72, 58.9);
            L(14.52, 85.6);
            S();
            M(13.98, 85.6);
            Qk(14.12, 86.9, 14.25, 87.4);
            S();
            M(14.52, 85.6);
            Qk(14.38, 86.9, 14.25, 87.4);
            S();
            細(() => { M(14.25, 59.5); L(14.25, 84.6); S(); });
        });
        // 左臂緩垂握柄，拳覆柄中；右叉腰
        const { 拳 } = 垂臂(bi, 筆, 1);
        武拳(bi, 筆, 拳[0], 拳[1], { 轉: Math.PI, 鏡: -1 });
        叉腰臂(bi, 筆, -1);
    },
    冠識(bi, 筆) {
        // 丑冠小識：橫角之牛——雙角外展・面郭・吻
        const { M, C, Qk, S, 細 } = 筆;
        細(() => bi.dim(0.8, () => {
            M(-0.35, 8.4);
            C(-1.0, 8.35, -1.45, 7.9, -1.55, 7.35);
            S();
            M(0.35, 8.4);
            C(1.0, 8.35, 1.45, 7.9, 1.55, 7.35);
            S();
            M(-0.35, 8.45);
            Qk(0, 8.2, 0.35, 8.45);
            S();
            M(-0.4, 8.95);
            Qk(0, 9.35, 0.4, 8.95);
            S();
        }));
    },
});
